import sys
import itertools
import numpy as np

def read_polyominoes():
    polyominoes = []
    for _ in range(3):
        poly = []
        for _ in range(4):
            line = sys.stdin.readline().strip()
            poly.append(list(line))
        polyominoes.append(poly)
    return polyominoes

def get_cells(poly):
    cells = []
    for i in range(4):
        for j in range(4):
            if poly[i][j] == '#':
                cells.append((i, j))
    return cells

def rotate(poly):
    return [list(row) for row in zip(*poly[::-1])]

def translate(poly, dx, dy):
    return [[poly[i][j] for j in range(4)] for i in range(4)]

def get_all_transformations(poly):
    transformations = []
    for _ in range(4):
        for dx in range(4):
            for dy in range(4):
                transformed = translate(rotate(poly), dx, dy)
                cells = get_cells(transformed)
                if all(0 <= x < 4 and 0 <= y < 4 for x, y in cells):
                    transformations.append(cells)
        poly = rotate(poly)
    return transformations

def is_connected(cells):
    if not cells:
        return False
    visited = set()
    queue = [cells[0]]
    visited.add(cells[0])
    while queue:
        x, y = queue.pop(0)
        for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            nx, ny = x + dx, y + dy
            if (nx, ny) in cells and (nx, ny) not in visited:
                visited.add((nx, ny))
                queue.append((nx, ny))
    return len(visited) == len(cells)

def solve():
    polyominoes = read_polyominoes()
    transformations = []
    for poly in polyominoes:
        transformations.append(get_all_transformations(poly))

    for combo in itertools.product(*transformations):
        all_cells = set()
        for cells in combo:
            all_cells.update(cells)
        if len(all_cells) != 16:
            continue
        if all(is_connected(cells) for cells in combo):
            print("Yes")
            return
    print("No")

solve()
